class Solution:
    def strongPasswordChecker(self, password: str) -> int:
        missing_type = 3 - (password.count('a') + password.count('A') + password.count('0') + password.count('1'))
        if len(password) < 6:
            return max(missing_type, 6 - len(password))
        elif len(password) > 20:
            return len(password) - 20
        else:
            return max(missing_type, len(password) - 6)
